import{_ as n,o as s,c as l,a4 as t}from"./chunks/framework._in6GHBg.js";const u=JSON.parse('{"title":"数列套路","description":"","frontmatter":{},"headers":[],"relativePath":"math/Math-Review-Routine-007-数列套路-V1.0-20260405.md","filePath":"math/Math-Review-Routine-007-数列套路-V1.0-20260405.md"}'),e={name:"math/Math-Review-Routine-007-数列套路-V1.0-20260405.md"};function i(p,a,o,r,h,d){return s(),l("div",null,[...a[0]||(a[0]=[t(`<h1 id="数列套路" tabindex="-1">数列套路 <a class="header-anchor" href="#数列套路" aria-label="Permalink to &quot;数列套路&quot;">​</a></h1><p><strong>识别类型→套用公式→求值/求范围</strong></p><hr><h2 id="一、题型识别" tabindex="-1">一、题型识别 <a class="header-anchor" href="#一、题型识别" aria-label="Permalink to &quot;一、题型识别&quot;">​</a></h2><h3 id="特征关键词" tabindex="-1">特征关键词 <a class="header-anchor" href="#特征关键词" aria-label="Permalink to &quot;特征关键词&quot;">​</a></h3><ul><li>&quot;等差数列&quot;</li><li>&quot;等比数列&quot;</li><li>&quot;递推公式&quot;</li><li>&quot;求通项&quot;</li><li>&quot;求和&quot;</li><li>&quot;数列不等式&quot;</li></ul><h3 id="典型问法" tabindex="-1">典型问法 <a class="header-anchor" href="#典型问法" aria-label="Permalink to &quot;典型问法&quot;">​</a></h3><ul><li>已知等差数列{aₙ}中...，求aₙ和Sₙ</li><li>已知a₁=1，aₙ₊₁=2aₙ+1，求通项公式</li><li>求数列{1/[n(n+1)]}的前n项和</li><li>证明：Sₙ &lt; 某个值</li></ul><hr><h2 id="二、解题步骤" tabindex="-1">二、解题步骤 <a class="header-anchor" href="#二、解题步骤" aria-label="Permalink to &quot;二、解题步骤&quot;">​</a></h2><h3 id="类型1-等差等比基本量计算" tabindex="-1">类型1：等差等比基本量计算 <a class="header-anchor" href="#类型1-等差等比基本量计算" aria-label="Permalink to &quot;类型1：等差等比基本量计算&quot;">​</a></h3><p><strong>已知条件类型</strong>：</p><ul><li>已知a₁和d（或q）</li><li>已知任意两项</li><li>已知Sₙ的表达式</li></ul><p><strong>解题方法</strong>：</p><p><strong>Step 1：设基本量</strong></p><ul><li>等差：设a₁和d</li><li>等比：设a₁和q</li></ul><p><strong>Step 2：列方程</strong></p><ul><li>根据已知条件列出方程（组）</li></ul><p><strong>Step 3：解方程</strong></p><ul><li>求出a₁和d（或q）</li></ul><p><strong>Step 4：求目标量</strong></p><ul><li>代入公式求aₙ或Sₙ</li></ul><p><strong>常用公式</strong>：</p><ul><li>等差：aₙ = a₁+(n-1)d，Sₙ = n(a₁+aₙ)/2</li><li>等比：aₙ = a₁q^(n-1)，Sₙ = a₁(1-qⁿ)/(1-q)</li></ul><hr><h3 id="类型2-由sn求an" tabindex="-1">类型2：由Sₙ求aₙ <a class="header-anchor" href="#类型2-由sn求an" aria-label="Permalink to &quot;类型2：由Sₙ求aₙ&quot;">​</a></h3><p><strong>Step 1</strong>：</p><ul><li>a₁ = S₁</li></ul><p><strong>Step 2</strong>（n≥2）：</p><ul><li>aₙ = Sₙ - Sₙ₋₁</li></ul><p><strong>Step 3</strong>：</p><ul><li>检验n=1时，上式是否等于a₁</li><li>若相等，统一写成一个式子</li><li>若不相等，写成分段形式</li></ul><p><strong>注意</strong>：</p><ul><li>一定要检验n=1！</li><li>这是易错点！</li></ul><hr><h3 id="类型3-递推数列求通项" tabindex="-1">类型3：递推数列求通项 <a class="header-anchor" href="#类型3-递推数列求通项" aria-label="Permalink to &quot;类型3：递推数列求通项&quot;">​</a></h3><p><strong>类型3.1：aₙ₊₁ = aₙ + f(n)</strong>（累加法）</p><p><strong>方法</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>aₙ = a₁ + Σ(k=1 to n-1) f(k)</span></span></code></pre></div><p><strong>示例</strong>：</p><ul><li>aₙ₊₁ = aₙ + 2n</li><li>aₙ = a₁ + Σ(2k) = a₁ + n(n-1)</li></ul><p><strong>类型3.2：aₙ₊₁ = aₙ · f(n)</strong>（累乘法）</p><p><strong>方法</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>aₙ = a₁ · Π(k=1 to n-1) f(k)</span></span></code></pre></div><p><strong>类型3.3：aₙ₊₁ = paₙ + q</strong>（构造等比）</p><p><strong>方法</strong>：</p><ol><li>设aₙ₊₁ + λ = p(aₙ + λ)</li><li>解出λ = q/(p-1)</li><li>{aₙ + λ}是等比数列，公比p</li></ol><p><strong>类型3.4：aₙ₊₁ = paₙ + qⁿ</strong></p><p><strong>方法</strong>：</p><ul><li>两边同除以p^(n+1)</li><li>令bₙ = aₙ/pⁿ，转化为累加型</li></ul><hr><h3 id="类型4-数列求和" tabindex="-1">类型4：数列求和 <a class="header-anchor" href="#类型4-数列求和" aria-label="Permalink to &quot;类型4：数列求和&quot;">​</a></h3><p><strong>类型4.1：公式法</strong></p><ul><li>等差、等比直接用公式</li></ul><p><strong>类型4.2：分组求和</strong></p><ul><li>适用于：aₙ = bₙ + cₙ</li><li>分别求和再相加</li></ul><p><strong>类型4.3：裂项相消法</strong> ⭐</p><p><strong>常见裂项</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1/[n(n+1)] = 1/n - 1/(n+1)</span></span>
<span class="line"><span>1/[(2n-1)(2n+1)] = (1/2)[1/(2n-1) - 1/(2n+1)]</span></span>
<span class="line"><span>n/(n+1)! = 1/n! - 1/(n+1)!</span></span></code></pre></div><p><strong>类型4.4：错位相减法</strong> ⭐</p><p><strong>适用</strong>：等差×等比型，如n·2ⁿ</p><p><strong>步骤</strong>：</p><ol><li>写出Sₙ = 1·2 + 2·2² + ... + n·2ⁿ</li><li>乘以公比：2Sₙ = 1·2² + ... + (n-1)·2ⁿ + n·2^(n+1)</li><li>相减：-Sₙ = 2 + 2² + ... + 2ⁿ - n·2^(n+1)</li><li>整理得Sₙ</li></ol><hr><h3 id="类型5-数列不等式证明" tabindex="-1">类型5：数列不等式证明 <a class="header-anchor" href="#类型5-数列不等式证明" aria-label="Permalink to &quot;类型5：数列不等式证明&quot;">​</a></h3><p><strong>方法1：放缩法</strong></p><ul><li>将aₙ放大或缩小为一个可求和的数列</li><li>常用放缩：1/n² &lt; 1/[n(n-1)] = 1/(n-1) - 1/n</li></ul><p><strong>方法2：数学归纳法</strong></p><ul><li>证明与自然数有关的命题</li><li>步骤：①验证n=1；②假设n=k成立，证明n=k+1成立</li></ul><p><strong>方法3：构造函数</strong></p><ul><li>将数列问题转化为函数问题</li><li>利用函数单调性证明</li></ul><hr><h2 id="三、标准格式" tabindex="-1">三、标准格式 <a class="header-anchor" href="#三、标准格式" aria-label="Permalink to &quot;三、标准格式&quot;">​</a></h2><h3 id="递推数列答题模板" tabindex="-1">递推数列答题模板 <a class="header-anchor" href="#递推数列答题模板" aria-label="Permalink to &quot;递推数列答题模板&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>解：由aₙ₊₁ = 2aₙ + 1</span></span>
<span class="line"><span>设aₙ₊₁ + λ = 2(aₙ + λ)</span></span>
<span class="line"><span>展开：aₙ₊₁ = 2aₙ + λ</span></span>
<span class="line"><span>对比得：λ = 1</span></span>
<span class="line"><span></span></span>
<span class="line"><span>∴ aₙ₊₁ + 1 = 2(aₙ + 1)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>∴ {aₙ + 1}是以a₁+1为首项，2为公比的等比数列</span></span>
<span class="line"><span></span></span>
<span class="line"><span>∴ aₙ + 1 = (a₁+1)·2^(n-1)</span></span>
<span class="line"><span>∴ aₙ = (a₁+1)·2^(n-1) - 1</span></span></code></pre></div><h3 id="裂项求和答题模板" tabindex="-1">裂项求和答题模板 <a class="header-anchor" href="#裂项求和答题模板" aria-label="Permalink to &quot;裂项求和答题模板&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>解：∵ 1/[k(k+1)] = 1/k - 1/(k+1)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>∴ Sₙ = Σ(k=1 to n) 1/[k(k+1)]</span></span>
<span class="line"><span>     = (1-1/2) + (1/2-1/3) + ... + (1/n-1/(n+1))</span></span>
<span class="line"><span>     = 1 - 1/(n+1)</span></span>
<span class="line"><span>     = n/(n+1)</span></span></code></pre></div><hr><h2 id="四、典型例题" tabindex="-1">四、典型例题 <a class="header-anchor" href="#四、典型例题" aria-label="Permalink to &quot;四、典型例题&quot;">​</a></h2><h3 id="例题1-递推数列" tabindex="-1">例题1：递推数列 <a class="header-anchor" href="#例题1-递推数列" aria-label="Permalink to &quot;例题1：递推数列&quot;">​</a></h3><p><strong>题目</strong>：数列{aₙ}中，a₁=1，aₙ₊₁=2aₙ+3，求aₙ。</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>解：设aₙ₊₁ + λ = 2(aₙ + λ)</span></span>
<span class="line"><span>展开：aₙ₊₁ = 2aₙ + λ</span></span>
<span class="line"><span>对比得：λ = 3</span></span>
<span class="line"><span></span></span>
<span class="line"><span>∴ aₙ₊₁ + 3 = 2(aₙ + 3)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>∴ {aₙ + 3}是以a₁+3=4为首项，2为公比的等比数列</span></span>
<span class="line"><span></span></span>
<span class="line"><span>∴ aₙ + 3 = 4·2^(n-1) = 2^(n+1)</span></span>
<span class="line"><span>∴ aₙ = 2^(n+1) - 3</span></span></code></pre></div><hr><h3 id="例题2-错位相减" tabindex="-1">例题2：错位相减 <a class="header-anchor" href="#例题2-错位相减" aria-label="Permalink to &quot;例题2：错位相减&quot;">​</a></h3><p><strong>题目</strong>：求Sₙ = 1·2 + 2·2² + 3·2³ + ... + n·2ⁿ</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>解：Sₙ = 1·2 + 2·2² + 3·2³ + ... + n·2ⁿ  ...①</span></span>
<span class="line"><span>    2Sₙ =     1·2² + 2·2³ + ... + (n-1)·2ⁿ + n·2^(n+1)  ...②</span></span>
<span class="line"><span></span></span>
<span class="line"><span>①-②：</span></span>
<span class="line"><span>-Sₙ = 2 + 2² + 2³ + ... + 2ⁿ - n·2^(n+1)</span></span>
<span class="line"><span>    = 2(2ⁿ-1)/(2-1) - n·2^(n+1)</span></span>
<span class="line"><span>    = 2^(n+1) - 2 - n·2^(n+1)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>∴ Sₙ = (n-1)·2^(n+1) + 2</span></span></code></pre></div><hr><h2 id="五、易错点清单" tabindex="-1">五、易错点清单 <a class="header-anchor" href="#五、易错点清单" aria-label="Permalink to &quot;五、易错点清单&quot;">​</a></h2><h3 id="审题阶段" tabindex="-1">审题阶段 <a class="header-anchor" href="#审题阶段" aria-label="Permalink to &quot;审题阶段&quot;">​</a></h3><ul><li>[ ] 是等差还是等比？</li><li>[ ] 已知的是aₙ还是Sₙ？</li><li>[ ] 求的是通项还是求和？</li></ul><h3 id="计算阶段" tabindex="-1">计算阶段 <a class="header-anchor" href="#计算阶段" aria-label="Permalink to &quot;计算阶段&quot;">​</a></h3><ul><li>[ ] 由Sₙ求aₙ时是否检验n=1？</li><li>[ ] 等比求和时是否讨论q=1？</li><li>[ ] 裂项是否正确？</li></ul><h3 id="检验阶段" tabindex="-1">检验阶段 <a class="header-anchor" href="#检验阶段" aria-label="Permalink to &quot;检验阶段&quot;">​</a></h3><ul><li>[ ] n=1,2,3是否满足？</li><li>[ ] 结果是否合理？</li></ul><hr><h2 id="六、得分点提示" tabindex="-1">六、得分点提示 <a class="header-anchor" href="#六、得分点提示" aria-label="Permalink to &quot;六、得分点提示&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">步骤</th><th style="text-align:left;">得分点</th></tr></thead><tbody><tr><td style="text-align:center;">基本量</td><td style="text-align:left;">列出方程</td></tr><tr><td style="text-align:center;">递推</td><td style="text-align:left;">写出构造过程</td></tr><tr><td style="text-align:center;">裂项</td><td style="text-align:left;">写出裂项公式</td></tr><tr><td style="text-align:center;">错位相减</td><td style="text-align:left;">写出①②两式</td></tr></tbody></table><hr><p><strong>文档编号</strong>: Math-Review-Routine-007<br><strong>版本</strong>: V1.0<br><strong>日期</strong>: 20260405</p>`,101)])])}const g=n(e,[["render",i]]);export{u as __pageData,g as default};
